102:   inline ScriptCounts(ScriptCounts&& src);
103:   inline ~ScriptCounts();
104: 
105:   inline ScriptCounts& operator=(ScriptCounts&& src);
106: 
107:   // Return the counter used to count the number of visits. Returns null if
108:   // the element is not found.
109:   PCCounts* maybeGetPCCounts(size_t offset);
110:   const PCCounts* maybeGetPCCounts(size_t offset) const;
111: 
112:   // PCCounts are stored at jump-target offsets. This function looks for the
113:   // previous PCCount which is in the same basic block as the current offset.
114:   PCCounts* getImmediatePrecedingPCCounts(size_t offset);
115: 
116:   // Return the counter used to count the number of throws. Returns null if
117:   // the element is not found.
118:   const PCCounts* maybeGetThrowCounts(size_t offset) const;
119: 
120:   // Throw counts are stored at the location of each throwing
121:   // instruction. This function looks for the previous throw count.
122:   //
123:   // Note: if the offset of the returned count is higher than the offset of
124:   // the immediate preceding PCCount, then this throw happened in the same
125:   // basic block.
126:   const PCCounts* getImmediatePrecedingThrowCounts(size_t offset) const;
127: 
128:   // Return the counter used to count the number of throws. Allocate it if
129:   // none exists yet. Returns null if the allocation failed.
130:   PCCounts* getThrowCounts(size_t offset);
